    uint32_t prev_stage_end;  // 上一阶段结束时间戳
    uint32_t log_offset;      // 串联日志在 DDR buffer 中的偏移
    uint32_t log_length;      // 串联日志长度
    uint8_t  boot_reason;     // 从 Preloader 传入
    uint8_t  boot_mode;       // NORMAL/RECOVERY/FASTBOOT...
    char     reserved2[10];
} boot_stage_marker_t;
```

